#!/usr/bin/env node
/**
 * build-registry-bundle.js
 * registry/ 내 모든 JSON을 window.REGISTRY_BUNDLE에 인라인한 JS 파일 생성.
 * 생성 위치: assets/js/registry-data-bundle.js
 * file:// 프로토콜 환경(로컬 서버 없이 HTML 직접 열기)에서도 동작하게 한다.
 */

const fs = require('fs');
const path = require('path');

const ROOT = path.resolve(__dirname, '..');

function readJson(relPath) {
  const abs = path.join(ROOT, relPath);
  if (!fs.existsSync(abs)) return null;
  try { return JSON.parse(fs.readFileSync(abs, 'utf8')); }
  catch { return null; }
}

const index = readJson('registry/index.json');
if (!index) { console.error('registry/index.json not found'); process.exit(1); }

const bundle = { index };

// tokens — index.tokens의 모든 키를 재귀적으로 처리
function resolveTokens(obj) {
  if (typeof obj === 'string') return readJson(obj);
  if (obj && typeof obj === 'object') {
    const result = {};
    for (const [k, v] of Object.entries(obj)) result[k] = resolveTokens(v);
    return result;
  }
  return obj;
}
bundle.tokens = resolveTokens(index.tokens);

// components
bundle.componentIndex = readJson(index.componentIndex);
bundle.components = {};
for (const [key, p] of Object.entries(index.components)) {
  bundle.components[key] = readJson(p);
}

// figma
bundle.figma = readJson(index.figma);

// governance
bundle.governance = {};
for (const [key, p] of Object.entries(index.governance)) {
  bundle.governance[key] = readJson(p);
}

// ai (optional)
if (index.ai) {
  bundle.ai = {};
  for (const [key, p] of Object.entries(index.ai)) {
    bundle.ai[key] = readJson(p);
  }
}

// reports index — data/reports-index.json (generated by reports:sync)
bundle.reportsIndex = readJson('data/reports-index.json');

const out = `/* AUTO-GENERATED — do not edit manually.
   Run: node scripts/build-registry-bundle.js
   This file inlines all registry JSON so pages work without a local HTTP server.
*/
window.REGISTRY_BUNDLE = ${JSON.stringify(bundle, null, 2)};
`;

const outPath = path.join(ROOT, 'assets/js/registry-data-bundle.js');
fs.writeFileSync(outPath, out, 'utf8');
console.log('✅  registry-data-bundle.js generated (' + Math.round(out.length / 1024) + ' KB)');
